map "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/NutritionFruitPortionsQuestionnaireResponseToObservation" = "NutritionFruitPortionsQuestionnaireResponseToObservation"

/// url = "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/NutritionFruitPortionsQuestionnaireResponseToObservation"
/// name = "NutritionFruitPortionsQuestionnaireResponseToObservation"
/// title = "Nutrition Fruit Portions Q to O"
/// status = "active"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QR as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Obs as target

imports "http://hl7.org/fhir/StructureMap/*"
imports "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/QuestionnaireResponseToObservationBase"

group NutritionFruitPortionsQuestionnaireResponseToObservation(source src : QR, target tgt : Obs) {
  src then SetObservationBase(src, tgt) "Base";
  src -> tgt.meta = create('Meta') as meta,
    meta.profile = 'https://fhir.hl7.at/prenudge/appdata/r4/StructureDefinition/at-prenudge-nutrition-fruitportions-observation' "SetProfile";
  src -> tgt.code = cc('http://loinc.org', '89765-5', 'Servings of fruit per day [PhenX]') "SetCode";
  src.item as item where linkId = 'DH2' then MapFruitPortions(item, tgt) "ProcessDH2";
}

group MapFruitPortions(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    answer.valueInteger as intObj then {
      intObj.value as numVal -> tgt.value = create('Quantity') as qty,
        qty.value = numVal,
        qty.unit = 'Portionen',
        qty.system = 'http://unitsofmeasure.org',
        qty.code = '{serving}' "SetQuantity";
    } "ExtractValue";
  } "ProcessAnswer";
}
